from microbit import *
import random

opcions = ['Pedra', 'Paper', 'Tisora']

while True:
    jugador = None
    if button_a.is_pressed() and button_b.is_pressed():
        jugador = 2   # Tisora
    elif button_a.is_pressed():
        jugador = 0   # Pedra
    elif button_b.is_pressed():
        jugador = 1   # Paper

    if jugador is not None:
        maquina = random.randint(0, 2)
        display.scroll(opcions[jugador])
        if jugador == maquina:
            display.scroll('Empat!')
        elif (jugador - maquina) % 3 == 1:
            display.scroll('GUANYES!')
        else:
            display.scroll('Perds...')
    sleep(200)

