from microbit import *

while True:
    llum = display.read_light_level()  # 0-255
    temp = temperature()               # graus Celsius

    display.scroll('L:' + str(llum) + ' T:' + str(temp), delay=60)

    if llum < 50:
        display.show(Image.ASLEEP)     # Molt fosc
    elif temp > 28:
        display.show(Image.SURPRISED)  # Molta calor
    else:
        display.show(Image.HAPPY)
    sleep(1500)

