# ESTACIÓ METEOROLÒGICA — Nivell 2
from microbit import *

lectures = []

def temp_calibrada():
    return temperature() - 3

def mitjana(lista):
    if len(lista) == 0: return 0
    return sum(lista) / len(lista)

def registrar():
    t = temp_calibrada()
    lectures.append(t)
    if len(lectures) > 10: lectures.pop(0)
    return t

def mostrar_stats():
    if not lectures:
        display.scroll('Sense dades'); return
    display.scroll('Mitj:' + str(round(mitjana(lectures), 1)))
    display.scroll('Max:' + str(max(lectures)))
    display.scroll('Min:' + str(min(lectures)))

while True:
    t = registrar()
    display.scroll(str(t) + 'C', delay=70)
    if button_a.was_pressed(): mostrar_stats()
    sleep(5000)

