# Botons gegants amb pins
from microbit import *

# Pins 0 i 1 com a entrades (botons)
# Connectar pin 0 a GND per pitjar botó GEGANT (ex: pinça a pin 0, una altra a P0)
# Connectar pin 1 a GND per pitjar botó GEGANT (ex: pinça a pin 1, una altra a P1)

while True:
    if pin0.is_touched(): # Detecta si el pin està connectat a GND (pitjat)
        display.show(Image.YES)
    elif pin1.is_touched():
        display.show(Image.NO)
    else:
        display.clear()
    sleep(50)
